import {
  NavLink
} from 'react-router-dom';

function Sidebar() {
  return (
    <div className="sidebar">
      <h2>FlowDesk</h2>

      <NavLink to="/">
        📊 Dashboard
      </NavLink>

      <NavLink to="/leads">
        👨‍🎓 Leads
      </NavLink>

      <NavLink to="/reports">
        📈 Reports
      </NavLink>

      <NavLink to="/settings">
        ⚙️ Settings
      </NavLink>
    </div>
  );
}

export default Sidebar;
